--
-- Table structure for table `ingredients`
--

CREATE TABLE `ingredients` (
  `id` int(11) NOT NULL,
  `ingredient_code` varchar(30) NOT NULL,
  `ingredient_name` varchar(150) NOT NULL,
  `category_id` int(11) DEFAULT NULL,
  `unit_of_measure` varchar(20) NOT NULL,
  `pack_size_value` decimal(10,3) DEFAULT NULL COMMENT 'Numeric size of one supplier pack, in the same unit family as unit_of_measure',
  `pack_size_unit` varchar(20) DEFAULT NULL COMMENT 'Unit of pack_size_value (kg/g/L/ml/pcs/pack/bottle). Should match unit_of_measure family.',
  `pack_label` varchar(50) DEFAULT NULL COMMENT 'Display label, e.g. "100 mL packet", "1 L bottle", "5 kg sack"',
  `minimum_stock` decimal(10,2) NOT NULL DEFAULT 0.00,
  `reorder_point` decimal(10,2) DEFAULT 0.00,
  `maximum_stock` decimal(10,2) DEFAULT NULL COMMENT 'Par level / order-up-to stock',
  `lead_time_days` int(11) DEFAULT 7,
  `current_stock` decimal(10,2) NOT NULL DEFAULT 0.00,
  `reserved_stock` decimal(10,2) DEFAULT 0.00,
  `available_stock` decimal(10,2) GENERATED ALWAYS AS (`current_stock` - `reserved_stock`) STORED,
  `unit_cost` decimal(10,2) DEFAULT NULL,
  `market_price` decimal(12,2) DEFAULT NULL,
  `last_price_update` date DEFAULT NULL,
  `storage_location` varchar(100) DEFAULT NULL,
  `storage_requirements` text DEFAULT NULL,
  `shelf_life_days` int(11) DEFAULT NULL,
  `is_perishable` tinyint(1) NOT NULL DEFAULT 1,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `enforce_whole_packs` tinyint(1) NOT NULL DEFAULT 0 COMMENT '1 = requests for this ingredient must be in whole packs (or break_pack_acknowledged)'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

